{
  "lean_declaration": "/-- Simple transposition `s_i` fixes any `k ≠ i, i+1`. (def.perm.si) -/\ntheorem simpleTransposition_apply_of_ne_ne {n : ℕ} (i : Fin (n - 1)) (k : Fin n) (h1 : k ≠ ⟨i.val, Nat.lt_of_lt_of_le i.isLt (Nat.sub_le n 1)⟩) (h2 : k ≠ ⟨i.val + 1, by omega⟩) : simpleTransposition i k = k := by\n  simpa [simpleTransposition] using Equiv.swap_apply_of_ne_of_ne h1 h2",
  "declaration_name": "simpleTransposition_apply_of_ne_ne",
  "used_context": [
    "simpleTransposition",
    "Equiv.swap_apply_of_ne_of_ne"
  ],
  "notes": [
    "Use `Equiv.swap_apply_of_ne_of_ne` lemma; `simp [h1, h2]` does not apply them."
  ]
}
